String osCommand;

if (System.getProperty("os.name").toLowerCase().contains("win")) {
    osCommand = "c:\\WINDOWS\\SYSTEM32\\cmd.exe /c dir ";
} else {
    osCommand = "/bin/ls ";
}

Process process = Runtime.getRuntime().exec(osCommand + input);
process.waitFor();

