Process process;

if (System.getProperty("os.name").toLowerCase().contains("win")) {
    process = new ProcessBuilder("cmd.exe", "/c", "dir", input).start();
} else {
    process = new ProcessBuilder("/bin/ls", input).start();
}

process.waitFor();
